77	// beadAutoCommit commits .ddx/beads.jsonl when configured by git.auto_commit.
78	// The operation string describes what happened (e.g. "create ddx-abc123").
79	// When a commit lands, the resulting SHA is returned.
80	func (f *CommandFactory) beadAutoCommit(operation string) (string, error) {
81		return f.beadAutoCommitWithMode(operation, false)
82	}
