92	func (f *CommandFactory) beadAutoCommitWithMode(operation string, includeStaged bool) (string, error) {
93		workspaceRoot := f.beadWorkspaceRoot()
94		if workspaceRoot == "" {
95			workspaceRoot = f.WorkingDir
96		}
97		beadsFile := filepath.Join(workspaceRoot, ".ddx", "beads.jsonl")
98		return f.beadAutoCommitPathsWithMode(operation, []string{beadsFile}, includeStaged)
99	}
