101	func (f *CommandFactory) beadAutoCommitPathsWithMode(operation string, paths []string, includeStaged bool) (string, error) {
102		workspaceRoot := f.beadWorkspaceRoot()
103		if workspaceRoot == "" {
104			workspaceRoot = f.WorkingDir
105		}
106	
107		cfg, err := config.LoadWithWorkingDir(workspaceRoot)
108		if err != nil {
109			return "", fmt.Errorf("load config for bead auto-commit: %w", err)
110		}
111		if cfg.Git == nil {
112			return "", nil
113		}
114		acCfg := gitpkg.AutoCommitConfig{
115			AutoCommit:    cfg.Git.AutoCommit,
116			CommitPrefix:  cfg.Git.CommitPrefix,
117			IncludeStaged: includeStaged,
118		}
119		sha, err := gitpkg.AutoCommitFiles(paths, "beads", operation, acCfg)
120		if err != nil {
121			return "", fmt.Errorf("auto-commit beads tracker after %s: %w", operation, err)
122		}
123		return sha, nil
124	}
