182	// commitIsMetadataOnlyTrackerBackfill reports whether the given commit changed
183	// only bead tracker state. Closing provenance is suppressed only for pure
184	// tracker backfills that touch .ddx/beads.jsonl and nothing else.
185	func (f *CommandFactory) commitIsMetadataOnlyTrackerBackfill(commitSHA string) bool {
186		if commitSHA == "" {
187			return false
188		}
189	
190		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
191		defer cancel()
192	
193		cmd := gitpkg.Command(ctx, f.WorkingDir, "show", "--pretty=format:", "--name-only", commitSHA)
194		out, err := cmd.Output()
195		if err != nil {
196			return false
197		}
198	
199		for _, line := range strings.Split(string(out), "\n") {
200			path := strings.TrimSpace(line)
201			if path == "" {
202				continue
203			}
204			if path != ".ddx/beads.jsonl" {
205				return false
206			}
207		}
208	
209		return true
210	}
