212	func isReviewCloseBead(b *bead.Bead) bool {
213		if b == nil {
214			return false
215		}
216		for _, label := range b.Labels {
217			switch label {
218			case "action:review", "kind:review", "phase:review", "review-finding":
219				return true
220			}
221		}
222		return false
223	}
