360	func (f *CommandFactory) newBeadShowCommand() *cobra.Command {
361		cmd := &cobra.Command{
362			Use:   "show <id>",
363			Short: "Show a bead",
364			Args:  cobra.ExactArgs(1),
365			RunE: func(cmd *cobra.Command, args []string) error {
366				s := f.beadStore()
367				b, err := s.GetWithArchive(args[0])
368				if err != nil {
369					return err
370				}
371	
372				asJSON, _ := cmd.Flags().GetBool("json")
373				if asJSON {
374					// Externalized events live in a sidecar; inline them for the
375					// JSON view so consumers (and the `events` UI projection)
376					// see a single uniform shape.
377					if err := s.LoadEventsInline(b); err != nil {
378						return err
379					}
380					data, err := bead.MarshalBead(*b)
381					if err != nil {
382						return err
383					}
384					var obj map[string]any
385					if err := json.Unmarshal(data, &obj); err != nil {
386						return err
387					}
388					workspaceRoot := f.beadWorkspaceRoot()
389					if workspaceRoot == "" {
390						workspaceRoot = f.WorkingDir
391					}
392					metrics, err := beadMetricsFor(workspaceRoot, b.ID)
393					if err != nil {
394						return err
395					}
396					if metrics == nil {
397						metrics = &beadMetricsSummary{}
398					}
399					obj["metrics"] = metrics
400					enc := json.NewEncoder(cmd.OutOrStdout())
401					enc.SetIndent("", "  ")
402					return enc.Encode(obj)
403				}
404	
405				out := cmd.OutOrStdout()
406				fmt.Fprintf(out, "ID:       %s\n", b.ID)
407				fmt.Fprintf(out, "Title:    %s\n", b.Title)
408				fmt.Fprintf(out, "Type:     %s\n", b.IssueType)
409				fmt.Fprintf(out, "Status:   %s\n", b.Status)
410				fmt.Fprintf(out, "Priority: %d\n", b.Priority)
411				if len(b.Labels) > 0 {
412					fmt.Fprintf(out, "Labels:   %s\n", strings.Join(b.Labels, ", "))
413				}
414				if b.Owner != "" {
415					fmt.Fprintf(out, "Owner:    %s\n", b.Owner)
416				}
417				if b.Parent != "" {
418					fmt.Fprintf(out, "Parent:   %s\n", b.Parent)
419				}
420				if len(b.Dependencies) > 0 {
421					fmt.Fprintf(out, "Deps:     %s\n", strings.Join(b.DepIDs(), ", "))
422				}
423				if b.Description != "" {
424					fmt.Fprintf(out, "Desc:     %s\n", b.Description)
425				}
426				if b.Acceptance != "" {
427					fmt.Fprintf(out, "Accept:   %s\n", b.Acceptance)
428				}
429				fmt.Fprintf(out, "Created:  %s\n", b.CreatedAt.Format("2006-01-02 15:04:05"))
430				fmt.Fprintf(out, "Updated:  %s\n", b.UpdatedAt.Format("2006-01-02 15:04:05"))
431				// Show agent session evidence if present
432				if b.Extra != nil {
433					if sessionID, ok := b.Extra["session_id"]; ok && sessionID != "" {
434						fmt.Fprintf(out, "Session:  %v\n", sessionID)
435						// Try to resolve session details
436						if sess := f.resolveAgentSession(fmt.Sprint(sessionID)); sess != nil {
437							fmt.Fprintf(out, "Harness:  %s\n", sess.Harness)
438							if sess.Model != "" {
439								fmt.Fprintf(out, "Model:    %s\n", sess.Model)
440							}
441							if sess.Tokens > 0 {
442								fmt.Fprintf(out, "Tokens:   %d (in: %d, out: %d)\n", sess.Tokens, sess.InputTokens, sess.OutputTokens)
443							}
444							if sess.CostUSD > 0 {
445								fmt.Fprintf(out, "Cost:     $%.4f\n", sess.CostUSD)
446							}
447							if sess.Duration > 0 {
448								fmt.Fprintf(out, "Duration: %dms\n", sess.Duration)
449							}
450						}
451					}
452					if commitSHA, ok := b.Extra["closing_commit_sha"]; ok && commitSHA != "" {
453						fmt.Fprintf(out, "Commit:   %v\n", commitSHA)
454					}
455					if v, ok := b.Extra["claimed-at"]; ok {
456						fmt.Fprintf(out, "Claimed:  %v\n", v)
457					}
458					if v, ok := b.Extra["claimed-machine"]; ok {
459						fmt.Fprintf(out, "Machine:  %v\n", v)
460					}
461					if v, ok := b.Extra["claimed-session"]; ok {
462						fmt.Fprintf(out, "Session:  %v\n", v)
463					}
464					if v, ok := b.Extra["claimed-worktree"]; ok {
465						fmt.Fprintf(out, "Worktree: %v\n", v)
466					}
467				}
468				claimKeys := map[string]bool{
469					"claimed-at": true, "claimed-pid": true,
470					"claimed-machine": true, "claimed-session": true, "claimed-worktree": true,
471					"session_id": true, "closing_commit_sha": true,
472				}
473				for k, v := range b.Extra {
474					if !claimKeys[k] {
475						fmt.Fprintf(out, "%s: %v\n", k, v)
476					}
477				}
478				return nil
479			},
480		}
481		cmd.Flags().Bool("json", false, "Output as JSON")
482		return cmd
483	}
