1113	func (f *CommandFactory) resolveNeedsHumanBead(id, action, note string, children []string) error {
1114		action = strings.TrimSpace(action)
1115		note = strings.TrimSpace(note)
1116		if note == "" {
1117			return fmt.Errorf("--note is required")
1118		}
1119		s := f.beadStore()
1120		switch action {
1121		case "retry":
1122			if err := s.UpdateWithLifecycleStatus(id, bead.StatusOpen, bead.LifecycleTransitionOptions{
1123				Reason: "human resolve retry",
1124				Actor:  resolveClaimAssignee(),
1125				Source: "ddx bead human resolve",
1126			}, func(b *bead.Bead) error {
1127				// Migration-only cleanup: removes LabelNeedsHuman from legacy rows;
1128				// new rows carry status=proposed rather than this label.
1129				removeBeadLabel(b, bead.LabelNeedsHuman)
1130				bead.SetNeedsHumanMeta(b, bead.NeedsHumanMeta{})
1131				return nil
1132			}); err != nil {
1133				return err
1134			}
1135			if err := appendNeedsHumanResolutionEvent(s, id, action, note, nil); err != nil {
1136				return err
1137			}
1138		case "split":
1139			children = normalizeChildIDs(children)
1140			if len(children) == 0 {
1141				return fmt.Errorf("--children is required when --action split")
1142			}
1143			if err := validateSplitChildren(s, id, children); err != nil {
1144				return err
1145			}
1146			for _, childID := range children {
1147				if err := s.DepAdd(id, childID); err != nil {
1148					return err
1149				}
1150			}
1151			if err := s.UpdateWithLifecycleStatus(id, bead.StatusOpen, bead.LifecycleTransitionOptions{
1152				Reason: "human resolve split",
1153				Actor:  resolveClaimAssignee(),
1154				Source: "ddx bead human resolve",
1155			}, func(b *bead.Bead) error {
1156				// Migration-only cleanup: removes LabelNeedsHuman from legacy rows;
1157				// new rows carry status=proposed rather than this label.
1158				removeBeadLabel(b, bead.LabelNeedsHuman)
1159				bead.SetNeedsHumanMeta(b, bead.NeedsHumanMeta{})
1160				return nil
1161			}); err != nil {
1162				return err
1163			}
1164			if err := appendNeedsHumanResolutionEvent(s, id, action, note, children); err != nil {
1165				return err
1166			}
1167		case "obsolete":
1168			if err := appendNeedsHumanResolutionEvent(s, id, action, note, nil); err != nil {
1169				return err
1170			}
1171			if err := s.Close(id); err != nil {
1172				return err
1173			}
1174		case "defer":
1175			if err := appendNeedsHumanResolutionEvent(s, id, action, note, nil); err != nil {
1176				return err
1177			}
1178		default:
1179			return fmt.Errorf("unknown --action %q (valid: retry, split, obsolete, defer)", action)
1180		}
1181		if _, err := f.beadAutoCommit("human resolve " + id); err != nil {
1182			return err
1183		}
1184		return nil
1185	}
