1187	func needsHumanRow(b bead.Bead) beadNeedsHumanRow {
1188		meta := bead.GetNeedsHumanMeta(b)
1189		return beadNeedsHumanRow{
1190			ID:              b.ID,
1191			Priority:        b.Priority,
1192			Title:           b.Title,
1193			Reason:          meta.Reason,
1194			Since:           meta.Since,
