1532	func (f *CommandFactory) newBeadMergeCommand() *cobra.Command {
1533		cmd := &cobra.Command{
1534			Use:   "merge [path]",
1535			Short: "Resolve a Git conflict in .ddx/beads.jsonl",
1536			Long: `Resolve a Git conflict in .ddx/beads.jsonl using DDx tracker rules.
1537	
1538	This is the supported escape hatch when Git leaves the bead tracker in an
1539	unmerged state. It reads the base, ours, and theirs versions from the Git
1540	index stages (:1:, :2:, :3:), merges records by bead id, preserves append-only
1541	events and dependency edges, writes the resolved JSONL file, and reports any
1542	scalar fields that required deterministic conflict resolution.
1543	
1544	This command is not a general hand-edit workflow for bead tracker data.`,
1545			Args: cobra.MaximumNArgs(1),
1546			RunE: func(cmd *cobra.Command, args []string) error {
1547				path := filepath.Join(".ddx", "beads.jsonl")
1548				if len(args) > 0 {
1549					path = args[0]
1550				}
1551				workspaceRoot := f.beadWorkspaceRoot()
1552				if workspaceRoot == "" {
1553					workspaceRoot = f.WorkingDir
1554				}
1555				repoRoot := gitpkg.FindProjectRoot(workspaceRoot)
1556				relPath, err := filepath.Rel(repoRoot, filepath.Join(workspaceRoot, path))
1557				if err != nil || strings.HasPrefix(relPath, ".."+string(filepath.Separator)) || relPath == ".." {
1558					relPath = filepath.ToSlash(path)
1559				}
1560				relPath = filepath.ToSlash(filepath.Clean(relPath))
1561	
1562				base, err := gitStageBlob(cmd.Context(), repoRoot, 1, relPath)
1563				if err != nil {
1564					return err
1565				}
1566				ours, err := gitStageBlob(cmd.Context(), repoRoot, 2, relPath)
1567				if err != nil {
1568					return err
1569				}
1570				theirs, err := gitStageBlob(cmd.Context(), repoRoot, 3, relPath)
1571				if err != nil {
1572					return err
1573				}
1574	
1575				merged, report, err := bead.MergeTrackerConflictJSONL(base, ours, theirs)
1576				if err != nil {
1577					return err
1578				}
1579				outPath := filepath.Join(repoRoot, relPath)
1580				if err := os.MkdirAll(filepath.Dir(outPath), 0o755); err != nil {
1581					return fmt.Errorf("bead merge: mkdir: %w", err)
1582				}
1583				if err := os.WriteFile(outPath, merged, 0o644); err != nil {
1584					return fmt.Errorf("bead merge: write %s: %w", relPath, err)
1585				}
1586	
1587				fmt.Fprintf(cmd.OutOrStdout(), "Merged %s: %d records (%d ours-only, %d theirs-only, %d same-id merged)\n",
1588					relPath, report.TotalRecords, report.PreservedOurs, report.PreservedTheirs, report.MergedRecords)
1589				for _, conflict := range report.ScalarConflicts {
1590					fmt.Fprintf(cmd.OutOrStdout(), "Resolved scalar conflict: %s.%s chose %s (%s)\n",
1591						conflict.ID, conflict.Field, conflict.Choice, conflict.Reason)
1592				}
1593				return nil
1594			},
1595		}
1596		return cmd
1597	}
