1599	func gitStageBlob(ctx context.Context, repoRoot string, stage int, path string) ([]byte, error) {
1600		spec := fmt.Sprintf(":%d:%s", stage, path)
1601		out, err := gitpkg.Command(ctx, repoRoot, "show", spec).Output()
1602		if err != nil {
1603			return nil, fmt.Errorf("bead merge: read Git stage %d for %s: %w", stage, path, err)
1604		}
1605		return out, nil
1606	}
