func evalMechanical(item Item, ctx Context) Entry {
	// When a backtick-quoted file path (containing /) is present and a FileInfo
	// hook is configured, check existence/rename mechanically.
	if ctx.FileInfo != nil {
		if m := backtickFilePathRE.FindStringSubmatch(item.Text); m != nil {
			path := m[1]
			_, existsAfter, renamedFrom := ctx.FileInfo(path)
			if existsAfter {
				evidence := fmt.Sprintf("file %q present in post-image", path)
				if renamedFrom != "" {
					evidence = fmt.Sprintf("file %q present; renamed from %q", path, renamedFrom)
				}
				return Entry{AC: item.AC, Kind: KindMechanical, Result: ResultPass, Evidence: evidence}
			}
			return Entry{AC: item.AC, Kind: KindMechanical, Result: ResultFail,
				Evidence: fmt.Sprintf("file %q not found in post-image; AC requires it", path)}
		}
	}
	// No resolvable path or no FileInfo hook: yield needs_judgment.
	return Entry{
		AC:       item.AC,
		Kind:     KindMechanical,
