// ParseACAliases scans text for lines of the form "AC #N: OldName -> NewName"
// and returns a map from 1-based AC number to the substituted name. The text
// is typically the bead's Description or Notes field.
func ParseACAliases(s string) map[int]string {
	result := make(map[int]string)
	scanner := bufio.NewScanner(strings.NewReader(s))
	for scanner.Scan() {
		if m := aliasLineRE.FindStringSubmatch(scanner.Text()); m != nil {
			var n int
			fmt.Sscanf(m[1], "%d", &n)
			if n > 0 {
				result[n] = m[2]
			}
		}
	}
	return result
}

